Bash(powershell -NoProfile -Command "
foreach \(\\$slug in @\('legales','cookies'\)\) {
  try {
    \\$r = Invoke-WebRequest -Uri \(\\"http://localhost/\\" + \\$slug + \\"/\\"\) -UseBasicParsing -TimeoutSec 10
    \\$has_h1 = \\$r.Content -match '<h1[^>]*>\(Legales|Cookies\)\\.'
    Write-Output \(\\$slug + ': STATUS ' + \\$r.StatusCode + ' | h1 match: ' + \\$has_h1\)
  } catch {
    Write-Output \(\\$slug + ': ERROR ' + \\$_.Exception.Message\)
  }
}
")

